from scipy.ndimage import gaussian_filter1dimport matplotlib.pyplot as pltdef find_active_regions(wavelength, opacity, threshold=0.1, smooth_sigma=70, show=False):    """    Identify wavelength intervals where the smoothed opacity exceeds    a given threshold.    Parameters    ----------    wavelength : ndarray        Wavelength grid (μm).    opacity : ndarray        Normalized opacity values.    threshold : float, default=0.1        Minimum smoothed opacity required for a wavelength to be        considered active.    smooth_sigma : float, default=70        Gaussian smoothing width in pixels. Larger values merge nearby        absorption features into broader molecular bands.    show : bool, default=False        If True, display the opacity spectrum before processing.    Returns    -------    list[tuple[float, float]]        List of (start, end) wavelength intervals in μm.    """        if show: _preview_opacity(wavelength, opacity)        opacity_smooth = gaussian_filter1d(opacity, sigma=smooth_sigma)        mask = opacity_smooth >= threshold    regions = []    inside = False    for wl, active in zip(wavelength, mask):        if active and not inside:            start = wl            inside = True        elif not active and inside:            regions.append((start, wl))            inside = False    if inside:        regions.append((start, wavelength[-1]))            regions = merge_regions(regions)        return regionsdef merge_regions(regions, min_gap_um=0.05):    """    Merge neighbouring active regions separated by less than    ``min_gap_nm``.    Parameters    ----------    regions : list[tuple[float, float]]        Active wavelength intervals.    min_gap_nm : float, default=0.05        Maximum gap between neighbouring regions before they are merged.    Returns    -------    list[tuple[float, float]]        Merged wavelength intervals.    """    if not regions:        return regions    merged = [regions[0]]    for start, end in regions[1:]:        if start - merged[-1][1] < min_gap_um:            merged[-1] = (merged[-1][0], end)  # extend previous region        else:            merged.append((start, end))    return mergeddef _preview_opacity(wavelength, opacity):    """    Display the opacity spectrum used to determine active regions.    """        print("Plotting...")    _, ax = plt.subplots(figsize=(12, 6))    ax.plot(wavelength, opacity)        ax.set_xlim(wavelength.min(), wavelength.max())    ax.set_ylim(opacity.min(), opacity.max())    ax.set_ylabel("Opacity")    ax.set_xlabel("Wavelength (μm)")    plt.show()    